// Method to check if two trees are mirrors of each other
private static boolean isMirror(Node left, Node right) {
    if (left == null && right == null) return true;
    if (left == null || right == null) return false;
    return isMirror(left.left, right.right) && 
           isMirror(left.right, right.left);
}

// Method to check if the tree is a mirror of itself
private static void isMirrorTree(Node root) {
    if (root == null) {
        System.out.println("YES");
        return;
    }
    boolean check = isMirror(root.left, root.right);
    if (check) {
        System.out.println("YES");
    } else {
        System.out.println("NO");
    }
}

